import java.util.*;
class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.nextLine();
        int first = -1, second = -1;
        for (int i = 0; i < s.length(); i++) {
            int count = 0;
            for (int j = 0; j < s.length(); j++) {
                if (s.charAt(i) == s.charAt(j))
                    count++;
            }
            if (count == 1) {
                if (first == -1)
                    first = i;
                else {
                    second = i;
                    break;
                }
            }
        }
        if (first != -1 && second != -1) {
            System.out.println(first + " - " + s.charAt(first));
            System.out.println(second + " - " + s.charAt(second));
        } else {
            System.out.print("-1");
        }
    }
}
